import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it.todo("empty item list -> premium 5 G (only processing fee)");

  // --- Base premiums for main items ---
  it.todo("single sword -> premium 105 G (100 base + 5 fee)");
  it.todo("single amulet -> premium 65 G (60 base + 5 fee)");
  it.todo("single staff -> premium 85 G (80 base + 5 fee)");
  it.todo("single potion -> premium 45 G (40 base + 5 fee)");

  // --- Components base premiums ---
  it.todo("2 runes -> 50 G base premium + fee = 55 G");
  it.todo("3 runes -> 60 G base premium (block applies) + fee = 65 G");
  it.todo("4 runes -> 100 G base premium (no block) + fee = 105 G");
  it.todo("7 runes -> 175 G base premium + fee = 180 G");
  it.todo("'alike' means same type: 2 runes + 1 moonstone -> 75 G base + fee = 80 G");
  it.todo("3 runes + 3 moonstones -> 120 G base (two separate blocks) + fee = 125 G");

  // --- Premium modifiers in isolation ---
  it.todo("cursed sword -> 100 + 50 curse + 5 fee = 155 G");
  it.todo("highly enchanted sword (enchantment 5) -> 100 + 30 + 5 fee = 135 G");
  it.todo("sword with enchantment 4 -> no high-enchantment surcharge = 105 G");
  it.todo("cursed sword with enchantment 5 -> both surcharges apply = 100 + 50 + 30 + 5 = 185 G");
  it.todo("long-standing customer (2 years) -> 20% loyalty discount applies");
  it.todo("first insurance carries 10% surcharge");
  it.todo("follow-up contract -> 15% discount on each contract after first");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet -> 210 G before fee (curse 50% of sword only)");

  // --- Rounding ---
  it.todo("premium calculation 197.5 G -> 198 G (rounded up in MHPCO favor)");

  // --- Edge cases for quote ---
  it.todo("quote with unknown item type -> exits non-zero, error to stderr");

  // --- Claim processing - basic ---
  it.todo("standard sword (steel, enchantment 3), damage 500 G -> payout 400 G");
  it.todo("damage to rune (insurance 250 G), damage 200 G -> payout 100 G");

  // --- Claim - special clauses ---
  it.todo("dragon-material sword, enchantment 5, damage 800 G -> payout 700 G (dragon full, then deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G -> payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G -> payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 8, damage 1000 G -> payout 400 G (high-enchantment clause)");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) -> payout 600 G (deductible per item)");

  // --- Multiple items of same type ---
  it.todo("policy covers two swords -> insurance sum 2000 G, cap 4000 G");
  it.todo("two swords, dragon attack damages both -> each has own deductible");
  it.todo("damages array has more entries of a type than insured -> CLI exits non-zero");

  // --- Cap exhaustion ---
  it.todo("sword + amulet -> insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword -> cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) -> insurance sum 1750 G");
  it.todo("two successive 1500 G claims on sword -> first payout 1400, second 600 (cap exhausted)");

  // --- Rounding payouts ---
  it.todo("payout calculation 350.5 G -> 350 G (rounded down in MHPCO favor)");

  // --- Edge cases for claim ---
  it.todo("claim references item not in policy -> CLI exits non-zero with stderr");
  it.todo("claim references unknown item type -> CLI exits non-zero");
  it.todo("claim has negative damage amount -> CLI exits non-zero");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, ench 3) -> premium 165 G");
  it.todo("long-standing customer's second contract cursed sword (ench 7) -> premium 160 G");
});

