type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: "quote"; items: Array<{ type: string }> }>;
};

export const runScenario = (input: Scenario): { results: Array<{ premium: number }> } => {
  const results = input.steps.map((step) => {
    const base = step.items.reduce((sum, item) => {
      if (item.type === "sword") return sum + 100;
      return sum;
    }, 0);
    return { premium: base + 5 };
  });
  return { results };
};

