type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: "quote"; items: Array<{ type: string }> }>;
};

const PROCESSING_FEE = 5;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const basePremiumFor = (itemType: string): number =>
  BASE_PREMIUM_BY_ITEM_TYPE[itemType] ?? 0;

const RUNE_BLOCK_SIZE = 3;

input.oldString:
const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_DISCOUNT = 15;

const basePremiumForItems = (items: Array<{ type: string }>): number => {
  const standardSum = items.reduce((sum, item) => sum + basePremiumFor(item.type), 0);
  const runeCount = items.filter((item) => item.type === "rune").length;
  const blockDiscount = runeCount === RUNE_BLOCK_SIZE ? RUNE_BLOCK_DISCOUNT : 0;
  return standardSum - blockDiscount;
};

input.newString:
const COMPONENT_TYPES = ["rune", "moonstone"];
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_DISCOUNT = 15;

const basePremiumForItems = (items: Array<{ type: string }>): number => {
  const standardSum = items.reduce((sum, item) => sum + basePremiumFor(item.type), 0);
  const totalBlockDiscount = COMPONENT_TYPES.reduce((discount, componentType) => {
    const count = items.filter((item) => item.type === componentType).length;
    return discount + (count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_DISCOUNT : 0);
  }, 0);
  return standardSum - totalBlockDiscount;
};

