const LOYALTY_YEARS_THRESHOLD = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;

const quotePremium = (items: Array<Item>, customer: Customer): number => {
  const policyBase = basePremiumForItems(items);
  const loyaltyDiscount =
    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
      ? policyBase * LOYALTY_DISCOUNT_RATE
      : 0;
  return policyBase - loyaltyDiscount + PROCESSING_FEE;
};

export const runScenario = (input: Scenario): { results: Array<{ premium: number }> } => {
  const results = input.steps.map((step) => ({
    premium: quotePremium(step.items, input.customer),
  }));
  return { results };
};

