const LOYALTY_YEARS_THRESHOLD = 2;
const LOYALTY_DISCOUNT_RATE = -0.2;
const FOLLOWUP_CONTRACT_DISCOUNT_RATE = -0.15;

type PolicyContext = { customer: Customer; quoteIndex: number };
type PolicyModifier = { applies: (ctx: PolicyContext) => boolean; rate: number };

const POLICY_MODIFIERS: Array<PolicyModifier> = [
  {
    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
    rate: LOYALTY_DISCOUNT_RATE,
  },
  {
    applies: () => true,
    rate: FIRST_INSURANCE_SURCHARGE_RATE,
  },
  {
    applies: (ctx) => ctx.quoteIndex > 0,
    rate: FOLLOWUP_CONTRACT_DISCOUNT_RATE,
  },
];

const policyModifierTotal = (subtotal: number, ctx: PolicyContext): number =>
  POLICY_MODIFIERS.reduce(
    (sum, modifier) => sum + (modifier.applies(ctx) ? subtotal * modifier.rate : 0),
    0,
  );

const roundUp = (amount: number): number => Math.ceil(amount);

const quotePremium = (items: Array<Item>, ctx: PolicyContext): number => {
  const subtotal = itemsSubtotal(items);
  const policyModifierBase = policyBasePremium(items);
  return roundUp(subtotal + policyModifierTotal(policyModifierBase, ctx) + PROCESSING_FEE);
};

export const runScenario = (input: Scenario): { results: Array<{ premium: number }> } => {
  let quoteIndex = 0;
  const results = input.steps.map((step) => {
    const result = { premium: quotePremium(step.items, { customer: input.customer, quoteIndex }) };
    quoteIndex += 1;
    return result;
  });
  return { results };
};

