type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
type Customer = { yearsWithMHPCO: number };
type Damage = { itemType: string; amount: number };
type QuoteStep = { op: "quote"; items: Array<Item> };
type ClaimStep = {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: Array<Damage> };
};
type Step = QuoteStep | ClaimStep;
type Scenario = {
  customer: Customer;
  steps: Array<Step>;
};
type QuoteResult = { premium: number };
type ClaimResult = { payout: number; remainingCap: number };
type StepResult = QuoteResult | ClaimResult;

const PROCESSING_FEE = 5;
const DEDUCTIBLE = 100;

input.oldString:
const payoutForDamage = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const applyClaim = (
  policy: Policy,
  damages: Array<Damage>,
): { result: ClaimResult; policy: Policy } => {
  const totalPayout = damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
  const newRemaining = policy.remainingCap - cappedPayout;
  return {
    result: { payout: roundDown(cappedPayout), remainingCap: newRemaining },
    policy: { ...policy, remainingCap: newRemaining },
  };
};

