input.newString:
const validateDamages = (policy: Policy, damages: Array<Damage>): void => {
  const counts = new Map<string, number>();
  for (const d of damages) {
    counts.set(d.itemType, (counts.get(d.itemType) ?? 0) + 1);
  }
  for (const [itemType, count] of counts) {
    const insured = countOfType(policy.items, itemType);
    if (count > insured) {
      throw new Error(
        `Too many damages of type ${itemType}: ${count} damages but only ${insured} insured`,
      );
    }
  }
};

const applyClaim = (
  policy: Policy,
  damages: Array<Damage>,
): { result: ClaimResult; policy: Policy } => {
  validateDamages(policy, damages);
  const totalPayout = damages.reduce(
    (sum, d) => sum + payoutForDamage(findItem(policy, d.itemType), d),
    0,
  );

